class Solution:
    def rearrangeSticks(self, n, k):
        MOD = 10**9 + 7
        # full 2D table of unsigned Stirling numbers of the first kind
        dp = [[0] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 1
        for i in range(1, n + 1):
            top = min(i, k)
            for j in range(1, top + 1):
                dp[i][j] = (dp[i - 1][j - 1] + (i - 1) * dp[i - 1][j]) % MOD
        return dp[n][k] % MOD

