class Solution:
    def rearrangeSticks(self, n, k):
        MOD = 10**9 + 7
        prev = [0] * (k + 1)
        prev[0] = 1
        for i in range(1, n + 1):
            cur = [0] * (k + 1)
            top = min(i, k)
            for j in range(1, top + 1):
                cur[j] = (prev[j - 1] + (i - 1) * prev[j]) % MOD
            prev = cur
        return prev[k]

