var rearrangeSticks = function(n, k) {
    const MOD = 1000000007n;
    let prev = new Array(k + 1).fill(0n);
    prev[0] = 1n;
    for (let i = 1; i <= n; i++) {
        const cur = new Array(k + 1).fill(0n);
        const top = Math.min(i, k);
        const im1 = BigInt(i - 1);
        for (let j = 1; j <= top; j++) {
            cur[j] = (prev[j - 1] + im1 * prev[j]) % MOD;
        }
        prev = cur;
    }
    return Number(prev[k]);
};
